// Merge config from either Master (body.config) or Sheet reads.
// Also merge Meta Ads specific config.

const webhookData = $('Webhook Trigger').first().json.body || {};

let config = {};
let metaAdsConfig = {};

if (webhookData.config) {
  // Master provided config
  config = webhookData.config;
  metaAdsConfig = webhookData.meta_ads_config || {};
} else {
  // Standalone: build config from Sheet rows
  try {
    const konfigRows = $('Konfig aus Sheet lesen').all();
    for (const row of konfigRows) {
      const key = (row.json['Einstellung'] || row.json['einstellung'] || '').trim();
      const val = (row.json['Wert'] || row.json['wert'] || '').trim();
      if (key) config[key] = val;
    }
  } catch (e) {
    // Konfig sheet read may not have run (Master path)
  }

  try {
    const adsRows = $('Meta Ads Konfig lesen').all();
    for (const row of adsRows) {
      const key = (row.json['Einstellung'] || row.json['einstellung'] || '').trim();
      const val = (row.json['Wert'] || row.json['wert'] || '').trim();
      if (key) metaAdsConfig[key] = val;
    }
  } catch (e) {
    // Meta Ads Konfig sheet read may not have run (Master path)
  }
}

// Calculate calendar week
const now = new Date();
const startOfYear = new Date(now.getFullYear(), 0, 1);
const days = Math.floor((now - startOfYear) / (24 * 60 * 60 * 1000));
const calendarWeek = Math.ceil((days + startOfYear.getDay() + 1) / 7);

return [{
  json: {
    config,
    metaAdsConfig,
    projectName: config.project_name || 'unknown',
    adAccountId: metaAdsConfig.ad_account_id || '',
    campaignFilter: metaAdsConfig.campaign_filter || '',
    dateRangeDays: parseInt(metaAdsConfig.date_range_days || '7'),
    enabled: (metaAdsConfig.enabled || 'FALSE').toUpperCase() === 'TRUE',
    calendarWeek,
    year: now.getFullYear(),
    timestamp: now.toISOString()
  }
}];

return [{
  json: {
    success: true,
    workflow: 'WF2 Meta Ads Analyzer',
    status: 'skipped',
    reason: 'Meta Ads Modul ist deaktiviert (enabled=FALSE in Meta Ads Konfig)',
    data: null,
    errors: null,
    timestamp: new Date().toISOString()
  }
}];

const input = $input.first().json;
const { adAccountId, campaignFilter, dateRangeDays, calendarWeek, year, projectName } = input;

if (!adAccountId) {
  throw new Error('ad_account_id fehlt in Meta Ads Konfig');
}

// Calculate date range
const endDate = new Date();
const startDate = new Date();
startDate.setDate(endDate.getDate() - dateRangeDays);

const formatDate = (d) => d.toISOString().split('T')[0];

// Meta Marketing API fields
const campaignFields = [
  'campaign_name', 'objective', 'status',
  'spend', 'impressions', 'clicks', 'ctr', 'cpc', 'cpm',
  'actions', 'action_values', 'reach', 'frequency'
].join(',');

const adsetFields = [
  'adset_name', 'campaign_name', 'status', 'targeting',
  'spend', 'impressions', 'clicks', 'ctr', 'cpc',
  'actions', 'reach', 'frequency'
].join(',');

const adFields = [
  'ad_name', 'adset_name', 'campaign_name', 'status',
  'spend', 'impressions', 'clicks', 'ctr', 'cpc', 'cpm',
  'actions', 'action_values', 'reach', 'frequency',
  'publisher_platform'
].join(',');

return [{
  json: {
    adAccountId,
    campaignFilter,
    calendarWeek,
    year,
    projectName,
    dateRangeStart: formatDate(startDate),
    dateRangeEnd: formatDate(endDate),
    timeRange: JSON.stringify({ since: formatDate(startDate), until: formatDate(endDate) }),
    campaignFields,
    adsetFields,
    adFields
  }
}];

// Consolidate campaign, ad set, and ad data from the 3 Graph API calls.
// Compute KPIs and identify top/bottom performers.

const apiParams = $('API-Parameter vorbereiten').first().json;
const { adAccountId, calendarWeek, year, projectName, dateRangeStart, dateRangeEnd } = apiParams;

// Safely extract data from each Graph API node
let campaigns = [];
let adsets = [];
let ads = [];

try {
  const campaignItems = $('Kampagnen abrufen').all();
  campaigns = campaignItems
    .map(i => i.json)
    .filter(d => d && !d.error && d.campaign_name);
} catch (e) {
  campaigns = [];
}

try {
  const adsetItems = $('Anzeigengruppen abrufen').all();
  adsets = adsetItems
    .map(i => i.json)
    .filter(d => d && !d.error && d.adset_name);
} catch (e) {
  adsets = [];
}

try {
  const adItems = $('Anzeigen abrufen').all();
  ads = adItems
    .map(i => i.json)
    .filter(d => d && !d.error && d.ad_name);
} catch (e) {
  ads = [];
}

// Helper: safely parse number
const num = (v) => parseFloat(v) || 0;

// Aggregate campaign-level KPIs
const totalSpend = campaigns.reduce((s, c) => s + num(c.spend), 0);
const totalImpressions = campaigns.reduce((s, c) => s + num(c.impressions), 0);
const totalClicks = campaigns.reduce((s, c) => s + num(c.clicks), 0);
const totalReach = campaigns.reduce((s, c) => s + num(c.reach), 0);

// Extract conversions from actions array
const getConversions = (actions) => !Array.isArray(actions) ? 0 : (() => { const purchase = actions.find(a => a.action_type === 'purchase' || a.action_type === 'offsite_conversion.fb_pixel_purchase'); const lead = actions.find(a => a.action_type === 'lead' || a.action_type === 'offsite_conversion.fb_pixel_lead'); return num(purchase?.value) + num(lead?.value); })();

const getConversionValue = (actionValues) => !Array.isArray(actionValues) ? 0 : (() => { const purchase = actionValues.find(a => a.action_type === 'purchase' || a.action_type === 'offsite_conversion.fb_pixel_purchase'); return num(purchase?.value); })();

const totalConversions = campaigns.reduce((s, c) => s + getConversions(c.actions), 0);
const totalConversionValue = campaigns.reduce((s, c) => s + getConversionValue(c.action_values), 0);

const overallCtr = totalImpressions > 0 ? (totalClicks / totalImpressions * 100) : 0;
const overallCpc = totalClicks > 0 ? (totalSpend / totalClicks) : 0;
const overallCpm = totalImpressions > 0 ? (totalSpend / totalImpressions * 1000) : 0;
const overallRoas = totalSpend > 0 ? (totalConversionValue / totalSpend) : 0;

// Rank ads by efficiency (spend-weighted CTR * ROAS or simple spend/conversions)
const rankedAds = ads
  .map(ad => ({
    name: ad.ad_name,
    adsetName: ad.adset_name,
    campaignName: ad.campaign_name,
    platform: ad.publisher_platform || 'unknown',
    spend: num(ad.spend),
    impressions: num(ad.impressions),
    clicks: num(ad.clicks),
    ctr: num(ad.ctr),
    cpc: num(ad.cpc),
    conversions: getConversions(ad.actions),
    conversionValue: getConversionValue(ad.action_values),
    roas: num(ad.spend) > 0 ? (getConversionValue(ad.action_values) / num(ad.spend)) : 0
  }))
  .filter(ad => ad.spend > 0)
  .sort((a, b) => b.roas - a.roas || b.ctr - a.ctr);

const top3 = rankedAds.slice(0, 3);
const bottom3 = rankedAds.slice(-3).reverse();

// Platform split (Facebook vs Instagram)
const fbAds = ads.filter(a => (a.publisher_platform || '').toLowerCase() === 'facebook');
const igAds = ads.filter(a => (a.publisher_platform || '').toLowerCase() === 'instagram');

const fbSpend = fbAds.reduce((s, a) => s + num(a.spend), 0);
const fbImpressions = fbAds.reduce((s, a) => s + num(a.impressions), 0);
const igSpend = igAds.reduce((s, a) => s + num(a.spend), 0);
const igImpressions = igAds.reduce((s, a) => s + num(a.impressions), 0);

return [{
  json: {
    adAccountId,
    projectName,
    calendarWeek,
    year,
    dateRangeStart,
    dateRangeEnd,
    summary: {
      totalCampaigns: campaigns.length,
      activeCampaigns: campaigns.filter(c => c.status === 'ACTIVE').length,
      totalSpend: Math.round(totalSpend * 100) / 100,
      totalImpressions,
      totalClicks,
      totalReach,
      totalConversions,
      totalConversionValue: Math.round(totalConversionValue * 100) / 100,
      overallCtr: Math.round(overallCtr * 10000) / 10000,
      overallCpc: Math.round(overallCpc * 100) / 100,
      overallCpm: Math.round(overallCpm * 100) / 100,
      overallRoas: Math.round(overallRoas * 10000) / 10000
    },
    top3Ads: top3,
    bottom3Ads: bottom3,
    platformSplit: {
      facebook: { spend: Math.round(fbSpend * 100) / 100, impressions: fbImpressions },
      instagram: { spend: Math.round(igSpend * 100) / 100, impressions: igImpressions }
    },
    rawCampaigns: campaigns,
    rawAdsets: adsets,
    rawAds: ads,
    adsCount: ads.length,
    hasData: campaigns.length > 0 || ads.length > 0
  }
}];

// Process Claude's analysis response and merge with consolidated data.
const adsData = $('Ads-Daten konsolidieren').first().json;
const claudeResponse = $input.first().json;

let analysisText = '';
let analysisJson = null;

try {
  // Claude API response structure: { content: [{ type: 'text', text: '...' }] }
  const content = claudeResponse.content;
  if (Array.isArray(content) && content.length > 0) {
    analysisText = content[0].text || '';
  } else if (typeof claudeResponse === 'string') {
    analysisText = claudeResponse;
  } else if (claudeResponse.error) {
    throw new Error(`Claude API Fehler: ${JSON.stringify(claudeResponse.error)}`);
  }

  // Try to parse as JSON (Claude was instructed to return JSON)
  try {
    // Remove markdown code fences if present
    let cleanText = analysisText.trim();
    if (cleanText.startsWith('```json')) {
      cleanText = cleanText.replace(/^```json\s*/, '').replace(/```\s*$/, '');
    } else if (cleanText.startsWith('```')) {
      cleanText = cleanText.replace(/^```\s*/, '').replace(/```\s*$/, '');
    }
    analysisJson = JSON.parse(cleanText);
  } catch (parseErr) {
    // If JSON parsing fails, store as text only
    analysisJson = { raw_text: analysisText, parse_error: parseErr.message };
  }
} catch (error) {
  analysisText = `Analyse-Fehler: ${error.message}`;
  analysisJson = { error: error.message };
}

// Build the Supabase record
return [{
  json: {
    project_name: adsData.projectName,
    calendar_week: adsData.calendarWeek,
    year: adsData.year,
    ad_account_id: adsData.adAccountId,
    total_campaigns: adsData.summary.totalCampaigns,
    active_campaigns: adsData.summary.activeCampaigns,
    total_spend: adsData.summary.totalSpend,
    total_impressions: adsData.summary.totalImpressions,
    total_clicks: adsData.summary.totalClicks,
    total_conversions: adsData.summary.totalConversions,
    overall_ctr: adsData.summary.overallCtr,
    overall_cpc: adsData.summary.overallCpc,
    overall_cpm: adsData.summary.overallCpm,
    overall_roas: adsData.summary.overallRoas,
    top_3_ads: JSON.stringify(adsData.top3Ads),
    bottom_3_ads: JSON.stringify(adsData.bottom3Ads),
    facebook_spend: adsData.platformSplit.facebook.spend,
    facebook_impressions: adsData.platformSplit.facebook.impressions,
    instagram_spend: adsData.platformSplit.instagram.spend,
    instagram_impressions: adsData.platformSplit.instagram.impressions,
    analysis_text: analysisText,
    analysis_json: JSON.stringify(analysisJson),
    raw_campaigns: JSON.stringify(adsData.rawCampaigns),
    raw_adsets: JSON.stringify(adsData.rawAdsets),
    raw_ads: JSON.stringify(adsData.rawAds),
    date_range_start: adsData.dateRangeStart,
    date_range_end: adsData.dateRangeEnd,
    collected_at: new Date().toISOString(),
    data_source: 'wf2_meta_ads_analyzer'
  }
}];

const adsData = $('Ads-Daten konsolidieren').first().json;
const analysisResult = $('Analyse-Ergebnis verarbeiten').first().json;

const errors = [];

// Check if we got actual data
if (!adsData.hasData) {
  errors.push({
    source: 'meta_api',
    message: 'Keine Kampagnendaten von Meta API erhalten. Moeglicherweise keine aktiven Kampagnen oder API-Zugriffsfehler.'
  });
}

// Check if Claude analysis succeeded
if (analysisResult.analysis_text && analysisResult.analysis_text.startsWith('Analyse-Fehler:')) {
  errors.push({
    source: 'claude_analysis',
    message: analysisResult.analysis_text
  });
}

return [{
  json: {
    success: errors.length === 0,
    workflow: 'WF2 Meta Ads Analyzer',
    status: errors.length === 0 ? 'success' : 'partial_success',
    data: {
      adAccountId: adsData.adAccountId,
      dateRange: `${adsData.dateRangeStart} bis ${adsData.dateRangeEnd}`,
      summary: adsData.summary,
      top3Ads: adsData.top3Ads.map(a => a.name),
      bottom3Ads: adsData.bottom3Ads.map(a => a.name),
      platformSplit: adsData.platformSplit,
      analysisAvailable: !analysisResult.analysis_text?.startsWith('Analyse-Fehler:'),
      supabaseWritten: true
    },
    errors: errors.length > 0 ? errors : null,
    timestamp: new Date().toISOString()
  }
}];
